942	static common_chat_params common_chat_params_init_gpt_oss(const common_chat_template &    tmpl,
943	                                                          const autoparser::generation_params & inputs) {
944	    common_chat_params data;
945	
946	    // Copy reasoning to the "thinking" field as expected by the gpt-oss template
947	    auto adjusted_messages = json::array();
948	    for (auto msg : inputs.messages) {
949	        if (msg.contains("reasoning_content") && msg.at("reasoning_content").is_string()) {
950	            msg["thinking"] = msg.at("reasoning_content");
951	            if (msg.contains("tool_calls") && msg.at("tool_calls").is_array() && !msg.at("tool_calls").empty()) {
952	                msg.erase("content");
953	            }
954	        }
955	        adjusted_messages.push_back(msg);
956	    }
957	
958	    auto prompt = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override= */ adjusted_messages);
959	
960	    // Check if we need to replace the return token with end token during
961	    // inference and without generation prompt. For more details see:
962	    // https://github.com/ggml-org/llama.cpp/issues/15417
963	    if (inputs.is_inference && !inputs.add_generation_prompt) {
964	        static constexpr std::string_view return_token = "<|return|>";
965	        static constexpr std::string_view end_token    = "<|end|>";
966	        if (size_t pos = prompt.rfind(return_token); pos != std::string::npos) {
967	            prompt.replace(pos, return_token.length(), end_token);
968	        }
969	    }
970	
971	    data.prompt            = prompt;
972	    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
973	    data.supports_thinking = true;
974	
975	    // These special tokens are required to parse properly, so we include them
976	    // even if parse_tool_calls is false.
977	    data.preserved_tokens = {
978	        "<|channel|>", "<|constrain|>", "<|message|>", "<|start|>", "<|end|>",
979	    };
980	
981	    auto has_tools           = inputs.tools.is_array() && !inputs.tools.empty();
982	    auto has_response_format = !inputs.json_schema.is_null() && inputs.json_schema.is_object();
983	    auto include_grammar     = has_response_format || (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE);
984	    auto extract_reasoning   = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
985	
986	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
987	        auto start           = p.rule("start", p.literal("<|start|>assistant"));
988	        auto end             = p.rule("end", p.literal("<|end|>"));
989	        auto content         = p.rule("message-content", p.until("<|end|>"));
990	        auto channel         = p.literal("<|channel|>") + (p.literal("commentary") | p.literal("analysis"));
991	        auto constrain_type  = p.chars("[A-Za-z0-9_-]", 1, -1);
992	
993	        // Occasionally, gpt-oss-20b will prefix channels with this commentary
994	        auto stray_commentary = p.optional(p.literal("<|channel|>commentary") + p.optional(p.literal(" to=assistant")));
995	        auto start_analysis = stray_commentary + p.literal("<|channel|>analysis<|message|>");
996	
997	        if (extract_reasoning) {
998	            p.rule("analysis", start_analysis + p.reasoning(content) + end);
999	        } else {
1000	            p.rule("analysis", p.content(start_analysis + content + end));
1001	        }
1002	
1003	        auto analysis = p.ref("analysis");
1004	        auto preamble = p.rule("preamble", p.literal("<|channel|>commentary<|message|>") + p.content(content) + end);
1005	        auto final_msg = p.rule("final", stray_commentary + p.literal("<|channel|>final<|message|>") + p.content(content));
1006	
1007	        // Consume any unsolicited tool calls, e.g. builtin functions
1008	        auto unsolicited = p.rule("unsolicited", p.atomic(p.optional(channel) + p.literal(" to=") + content + end));
1009	
1010	        auto any = p.rule("any", preamble | analysis);
1011	
1012	        if (has_response_format) {
1013	            auto constraint = p.optional(p.space() + p.optional(p.literal("<|constrain|>")) + constrain_type);
1014	            auto response_format = p.rule("response-format",
1015	                p.literal("<|channel|>final") + constraint + p.literal("<|message|>") +
1016	                p.content(p.schema(p.json(), "response-format-schema", inputs.json_schema)));
1017	
1018	            return p.zero_or_more(start + analysis) + start + response_format;
1019	        }
1020	
1021	        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
1022	            auto tool_choice = p.choice();
1023	
1024	            foreach_function(inputs.tools, [&](const json & tool) {
1025	                const auto & function = tool.at("function");
1026	                std::string  name     = function.at("name");
1027	                const auto & params   = function.at("parameters");
1028	
1029	                auto func_name  = p.literal(" to=functions.") + p.tool_name(p.literal(name));
1030	                auto constraint = p.optional(p.space() + p.optional(p.literal("<|constrain|>")) + constrain_type);
1031	                auto args       = p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", params));
1032	
1033	                // recipient in role header
1034	                //   <|start|>assistant to=functions.NAME<|channel|>(commentary|analysis)[constraint]<|message|>ARGS
1035	                auto tool_in_role = p.tool(p.tool_open(func_name + channel + constraint + p.literal("<|message|>")) + args);
1036	
1037	                // recipient in channel header
1038	                //   <|channel|>(commentary|analysis) to=functions.NAME[constraint]<|message|>ARGS
1039	                auto tool_in_channel = p.tool(p.tool_open(channel + func_name + constraint + p.literal("<|message|>")) + args);
1040	
1041	                tool_choice |= p.rule("tool-" + name, tool_in_role | tool_in_channel);
1042	            });
1043	
1044	            auto tool_call  = p.trigger_rule("tool-call", tool_choice);
1045	
1046	            if (inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED) {
1047	                return p.zero_or_more(start + any) + start + tool_call;
1048	            }
1049	
1050	            return p.zero_or_more(start + any) + start + (tool_call | final_msg);
1051	        }
1052	
1053	        return p.zero_or_more(start + any) + start + (final_msg | unsolicited);
1054	    });
1055	
1056	    data.parser = parser.save();
1057	
1058	    if (include_grammar) {
1059	        data.grammar_lazy = !(has_response_format || (has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED));
1060	        data.grammar      = build_grammar([&](const common_grammar_builder & builder) {
1061	            foreach_function(inputs.tools, [&](const json & tool) {
1062	                const auto & function = tool.at("function");
1063	                auto         schema   = function.at("parameters");
1064	                builder.resolve_refs(schema);
1065	            });
1066	            parser.build_grammar(builder, data.grammar_lazy);
1067	        });
1068	
1069	        data.grammar_triggers = {
1070	            { COMMON_GRAMMAR_TRIGGER_TYPE_PATTERN, "^\\s+to$" },
1071	            { COMMON_GRAMMAR_TRIGGER_TYPE_PATTERN, "^<\\|channel\\|>(?:commentary|analysis)\\s+to=functions$" },
1072	            { COMMON_GRAMMAR_TRIGGER_TYPE_PATTERN, "<\\|start\\|>assistant(\\s+to)" },
1073	            { COMMON_GRAMMAR_TRIGGER_TYPE_PATTERN, "<\\|start\\|>assistant(<\\|channel\\|>(?:commentary|analysis)\\s+to)" }
1074	        };
1075	    }
1076	
1077	    return data;
1078	}
