1261	            p.optional(p.literal(SECTION_BEGIN)) +
1262	            p.trigger_rule("tool-call", p.repeat(CALL_BEGIN + tool_choice, min_calls, max_calls) +
1263	                p.optional(p.literal(SECTION_END)))
1264	        );
1265	
1266	        auto content_before_tools = p.content(p.until_one_of({ SECTION_BEGIN, CALL_BEGIN }));
